diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9f034aba874a..382ae0538ff3 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -3345,7 +3345,37 @@ Instruction *InstCombinerImpl::foldICmpBinOpEqualityWithConstant(
         return new ICmpInst(Pred, BOp0, Neg);
       }
     }
-    break;
+    // icmp eq/ne (add (zext i1 X), (zext i1 Y)), 1 -> xor X, Y / not (xor X, Y)
+    // This is checking if exactly one of X and Y is true, which is XOR.
+    // The result of zext i1 is always 0 or 1, and 0+0=0, 0+1=1, 1+1=2 are all
+    // safely representable in any integer type, so nowrap flags are not needed.
+    if (C.isOne()) {
+      Value *X, *Y;
+      if (match(BOp0, m_ZExt(m_Value(X))) &&
+          match(BOp1, m_ZExt(m_Value(Y))) &&
+          X->getType()->isIntOrIntVectorTy(1) &&
+          Y->getType()->isIntOrIntVectorTy(1)) {
+        Value *Xor = Builder.CreateXor(X, Y);
+        if (Pred == ICmpInst::ICMP_EQ)
+          return replaceInstUsesWith(Cmp, Xor);
+        return BinaryOperator::CreateNot(Xor);
+      }
+    }
+
+    // icmp eq/ne (add (zext i1 X), (zext i1 Y)), 2 -> and X, Y / not (and X, Y)
+    // This is checking if both X and Y are true, which is AND.
+    if (C == 2) {
+      Value *X, *Y;
+      if (match(BOp0, m_ZExt(m_Value(X))) &&
+          match(BOp1, m_ZExt(m_Value(Y))) &&
+          X->getType()->isIntOrIntVectorTy(1) &&
+          Y->getType()->isIntOrIntVectorTy(1)) {
+        Value *And = Builder.CreateAnd(X, Y);
+        if (Pred == ICmpInst::ICMP_EQ)
+          return replaceInstUsesWith(Cmp, And);
+        return BinaryOperator::CreateNot(And);
+      }
+    }
   }
   case Instruction::Xor:
     if (BO->hasOneUse()) {

